class SynapticIntelligence:
    """
    Online importance estimation for sequential task training.
    No separate forward pass needed — importance accumulates during training.
    """
    def __init__(self, model, xi: float = 0.1, c: float = 0.5):
        self.model    = model
        self.xi       = xi        # damping to avoid division by zero
        self.c        = c         # regularisation strength
        # Omega: accumulated importance per parameter
        # W:     accumulated gradient * delta_theta per parameter
        self.omega  = {n: torch.zeros_like(p)
                       for n, p in model.named_parameters() if p.requires_grad}
        self.W      = {n: torch.zeros_like(p)
                       for n, p in model.named_parameters() if p.requires_grad}
        self.theta_star = {n: p.detach().clone()
                           for n, p in model.named_parameters() if p.requires_grad}
        self.prev_params = {n: p.detach().clone()
                            for n, p in model.named_parameters() if p.requires_grad}

    def update_W(self):
        """Call after each optimizer.step() — accumulates gradient * delta."""
        for name, param in self.model.named_parameters():
            if param.requires_grad and param.grad is not None:
                delta = param.detach() - self.prev_params[name].to(param.device)
                self.W[name] -= param.grad.detach() * delta   # negative because loss ↓
                self.prev_params[name] = param.detach().clone()

    def consolidate(self):
        """Call at end of each task — update Omega and reset W."""
        for name, param in self.model.named_parameters():
            if not param.requires_grad:
                continue
            delta_sq = (param.detach() - self.theta_star[name].to(param.device)) ** 2
            self.omega[name] += self.W[name] / (delta_sq + self.xi)
            self.omega[name].clamp_(min=0)
            self.W[name].zero_()
            self.theta_star[name] = param.detach().clone()

    def penalty(self) -> torch.Tensor:
        """SI regularisation term — add to task loss."""
        loss = torch.tensor(0.0, device=next(self.model.parameters()).device)
        for name, param in self.model.named_parameters():
            if param.requires_grad:
                diff = param - self.theta_star[name].to(param.device)
                loss += (self.omega[name].to(param.device) * diff ** 2).sum()
        return self.c * loss
